INSERT INTO wildlife_species (slug, name, scientific_name, description, class_type, conservation_status, nepal_status, habitat, elevation_range, estimated_population, is_endemic, is_featured, fun_facts) VALUES
('indian-cobra', 'Indian Cobra', 'Naja naja', 'One of the most recognized venomous snakes in South Asia, known for its iconic hood markings. Found across the Terai and mid-hills of Nepal.', 'REPTILE', 'LEAST_CONCERN', 'COMMON', 'Terai grasslands, farmlands, and scrub forests', '100-1500m', '50000', true, false, 'The Indian cobra is one of the ''Big Four'' venomous snakes responsible for the most snakebite deaths in South Asia.'),
('common-krait', 'Common Krait', 'Bungarus caeruleus', 'A highly venomous nocturnal snake with distinctive black and white bands. Responsible for more snakebite deaths in Nepal than any other species.', 'REPTILE', 'LEAST_CONCERN', 'COMMON', 'Terai lowlands, agricultural fields, and human settlements', '100-800m', '30000', true, false, 'The common krait is so dangerous because it often enters homes at night and bites sleeping people.'),
('russells-viper', 'Russell''s Viper', 'Daboia russelii', 'A large, heavily built venomous snake with a distinctive chain-like dorsal pattern. Found in grasslands and agricultural areas.', 'REPTILE', 'LEAST_CONCERN', 'COMMON', 'Terai grasslands, farmlands, and open forests', '100-1200m', '25000', false, false, 'Russell''s viper can produce up to 150mg of venom in a single bite, enough to kill 100 adults.'),
('white-lipped-pit-viper', 'White-lipped Pit Viper', 'Trimeresurus albolabris', 'A bright green venomous pit viper with a white or yellow lateral stripe. Found in forests and agricultural areas across Nepal.', 'REPTILE', 'LEAST_CONCERN', 'COMMON', 'Mid-hill forests, tea gardens, and bamboo groves', '500-2000m', '15000', false, false, 'White-lipped pit vipers are arboreal and use heat-sensing pits to detect warm-blooded prey.'),
('bamboo-pit-viper', 'Stejneger''s Bamboo Pit Viper', 'Trimeresurus stejnegeri', 'A venomous pit viper with green coloration that provides excellent camouflage in bamboo forests. Found in the eastern mid-hills.', 'REPTILE', 'LEAST_CONCERN', 'COMMON', 'Bamboo forests and dense vegetation', '800-2200m', '8000', false, false, 'This species changes shade between light and dark green depending on its surroundings.'),
('cat-eyed-snake', 'Cat-eyed Snake', 'Boiga trigonopus', 'A rear-fanged mildly venomous snake with large eyes and a cat-like appearance. Nocturnal and arboreal in nature.', 'REPTILE', 'LEAST_CONCERN', 'COMMON', 'Tropical and subtropical forests', '300-1800m', '6000', false, false, 'Cat-eyed snakes can flatten their bodies to appear larger when threatened.'),
('green-keelback', 'Green Keelback', 'Ahaetulla nasuta', 'A slender, bright green non-venomous snake with an elongated snout. Commonly seen in gardens and forests.', 'REPTILE', 'LEAST_CONCERN', 'COMMON', 'Gardens, farmlands, and forest edges', '200-1800m', '20000', false, false, 'Green keelbacks can change from bright green to yellow or brown based on mood and temperature.'),
('common-wolf-snake', 'Common Wolf Snake', 'Lycodon aulicus', 'A small, slender non-venomous snake with distinctive brown and white bands. Frequently found in houses.', 'REPTILE', 'LEAST_CONCERN', 'COMMON', 'Human dwellings, gardens, and forest edges', '100-2000m', '35000', false, false, 'Wolf snakes are excellent climbers and often enter homes to hunt geckos.'),
('jara-wolf-snake', 'Jara Wolf Snake', 'Lycodon jara', 'A small non-venomous snake endemic to the eastern Himalayas. Found in forest leaf litter and under rocks.', 'REPTILE', 'LEAST_CONCERN', 'COMMON', 'Subtropical and temperate forests', '800-2500m', '5000', false, false, 'This species is named after the Jara people who live in its native habitat.'),
('buff-striped-keelback', 'Buff-striped Keelback', 'Amphiesma stolatum', 'A harmless, mildly venomous keelback with buff-colored stripes. Common near water bodies.', 'REPTILE', 'LEAST_CONCERN', 'COMMON', 'Wetlands, rice paddies, and stream banks', '100-1500m', '30000', false, false, 'Buff-striped keelbacks feed primarily on frogs and are harmless to humans.'),
('checkered-keelback', 'Checkered Keelback', 'Amphiesma crux', 'A medium-sized keelback with a distinctive checkered pattern. Found near water in the Terai and mid-hills.', 'REPTILE', 'LEAST_CONCERN', 'COMMON', 'Wetlands, ponds, and rice fields', '100-1200m', '20000', false, false, 'This species is an excellent swimmer and can stay underwater for extended periods.'),
('forsten-cat-snake', 'Forsten''s Cat Snake', 'Boiga forsteni', 'A large, rear-fanged mildly venomous snake with a triangular head and large eyes. Nocturnal hunter.', 'REPTILE', 'LEAST_CONCERN', 'COMMON', 'Tropical forests and bamboo groves', '300-1500m', '7000', false, false, 'Forsten cat snakes can grow up to 2.5 meters and are known to be aggressive when cornered.'),
('indian-egg-eater', 'Indian Egg-eater', 'Oligodon arnensis', 'A small, harmless snake that feeds exclusively on eggs. Has specialized vertebral projections for crushing eggshells.', 'REPTILE', 'LEAST_CONCERN', 'COMMON', 'Farmlands, gardens, and forest edges', '200-1800m', '8000', false, false, 'Egg-eaters can swallow eggs much larger than their head by unhinging their jaws.'),
('mock-viper', 'Mock Viper', 'Psammodynastes pulverulentus', 'A small, mildly venomous snake that mimics the appearance of true vipers. Found in leaf litter.', 'REPTILE', 'LEAST_CONCERN', 'COMMON', 'Forest floors and rocky areas', '300-2000m', '6000', false, false, 'Mock vipers flatten their heads and hiss loudly to mimic dangerous vipers.'),
('beaked-sea-snake', 'Beaked Sea Snake', 'Enhydrina schistosa', 'A highly venomous sea snake with a distinctive beak-like snout. Found in coastal and riverine waters.', 'REPTILE', 'LEAST_CONCERN', 'RARE', 'Coastal waters and river deltas', '0-100m', '2000', false, false, 'Beaked sea snakes are responsible for the majority of sea snake bites worldwide.'),
('blue-coral-snake', 'Blue-lipped Sea Snake', 'Hydrophis cyanocinctus', 'A venomous sea snake with blue banding. Found in marine and estuarine environments.', 'REPTILE', 'LEAST_CONCERN', 'RARE', 'Coastal marine waters and estuaries', '0-50m', '1500', false, false, 'These snakes can dive to depths of over 100 meters and stay submerged for hours.'),
('brahminy-blindsnake', 'Brahminy Blindsnake', 'Ramphotyphlops braminus', 'A tiny, burrowing snake that is the only known parthenogenetic snake species. Widely distributed.', 'REPTILE', 'LEAST_CONCERN', 'COMMON', 'Gardens, farmlands, and moist soil', '0-2000m', '50000', false, false, 'All Brahminy blindsnakes are female and reproduce without males.'),
('dog-faced-water-snake', 'Dog-faced Water Snake', 'Cerberus rynchops', 'A mildly venomous water snake with a dog-like snout. Common in coastal and riverine habitats.', 'REPTILE', 'LEAST_CONCERN', 'COMMON', 'Coastal waters, mangroves, and river mouths', '0-100m', '3000', false, false, 'Dog-faced water snakes can tolerate brackish water and are excellent swimmers.'),
('short-sea-snake', 'Short-sea Snake', 'Cerberus microlepis', 'A small, mildly venomous sea snake found in shallow coastal waters. Nocturnal hunter.', 'REPTILE', 'LEAST_CONCERN', 'RARE', 'Shallow coastal waters and coral reefs', '0-30m', '1000', false, false, 'This species has reduced eyes compared to other sea snakes, relying more on smell.'),
('conic-snake', 'Rajesh Sand Boa', 'Gongylophis conicus', 'A thick-bodied, non-venomous burrowing snake with a distinctive conical head. Found in sandy areas.', 'REPTILE', 'LEAST_CONCERN', 'COMMON', 'Sandy soils, riverbeds, and arid regions', '100-800m', '4000', false, false, 'Sand boas can survive extreme temperatures by burrowing deep into sand.'),
('indian-rat-snake', 'Indian Brown Snake', 'Eryx johnii', 'A large, non-venomous constrictor with uniform brown coloration. Found in arid and semi-arid regions.', 'REPTILE', 'LEAST_CONCERN', 'COMMON', 'Dry forests, scrublands, and sandy areas', '200-1000m', '5000', false, false, 'Indian brown snakes can grow up to 1.8 meters and are powerful constrictors.'),
('whitakers-sand-boa', 'Whitaker''s Sand Boa', 'Eryx whitakeri', 'A rare, non-venomous sand boa endemic to parts of South Asia. Found in dry deciduous forests.', 'REPTILE', 'VULNERABLE', 'RARE', 'Dry deciduous forests and scrublands', '300-800m', '1500', false, false, 'Named after herpetologist Romulus Whitaker, this species is rarely encountered.'),
('striped-palatine', 'Striped Wolf Snake', 'Lycodon striatus', 'A small, non-venomous snake with dark brown and white stripes. Found in rocky and forested areas.', 'REPTILE', 'LEAST_CONCERN', 'COMMON', 'Rocky outcrops, forests, and stone walls', '500-2000m', '6000', false, false, 'Striped wolf snakes are excellent at squeezing into narrow rock crevices.'),
('brown-pit-viper', 'Brown Pit Viper', 'Ahaetulla pulverulenta', 'A brown-colored pit viper with heat-sensing pits. Found in forests and rocky areas of Nepal.', 'REPTILE', 'LEAST_CONCERN', 'COMMON', 'Forests, rocky slopes, and bamboo thickets', '600-2200m', '4000', false, false, 'Brown pit vipers are ambush predators that can remain motionless for hours.'),
('king-cobra-nepal', 'King Cobra', 'Ophiophagus hannah', 'The longest venomous snake in the world, capable of growing over 5 meters. Found in dense forests.', 'REPTILE', 'VULNERABLE', 'COMMON', 'Tropical and subtropical forests', '200-2000m', '3000', false, false, 'King cobras are the only snakes that build nests for their eggs.'),
('monocled-cobra', 'Monocled Cobra', 'Naja kaouthia', 'A highly venomous cobra with a distinctive monocle-shaped hood marking. Found across Nepal.', 'REPTILE', 'LEAST_CONCERN', 'COMMON', 'Farmlands, forests, and wetlands', '100-1200m', '15000', false, false, 'Monocled cobras can spit venom accurately up to 3 meters.'),
('banded-krait', 'Banded Krait', 'Bungarus fasciatus', 'A highly venomous krait with alternating black and yellow bands. Found in forests and farmlands.', 'REPTILE', 'LEAST_CONCERN', 'COMMON', 'Tropical forests, farmlands, and water bodies', '100-1000m', '5000', false, false, 'Banded kraits are more docile than other krait species during daytime.'),
('red-coral-snake', 'Red Coral Snake', 'Calliophis nigrescens', 'A small, mildly venomous coral snake with striking red and black coloration. Shy and secretive.', 'REPTILE', 'LEAST_CONCERN', 'RARE', 'Forest floors, leaf litter, and rocky areas', '500-2000m', '3000', false, false, 'Red coral snakes are so secretive they are rarely seen even by experienced herpetologists.'),
('golden-cobra', 'Gold-ringed Cat Snake', 'Boiga flaviceps', 'A rear-fanged, mildly venomous snake with golden-ringed patterns. Found in tropical forests.', 'REPTILE', 'LEAST_CONCERN', 'RARE', 'Tropical evergreen forests', '300-1200m', '2000', false, false, 'This nocturnal species has vertical pupils similar to cats.'),
('trinket-snake', 'Trinket Snake', 'Coelognathus helena', 'A large, non-venomous constrictor with beautiful trinket-like patterns. Found in forests and farmlands.', 'REPTILE', 'LEAST_CONCERN', 'COMMON', 'Dry forests, scrublands, and farmlands', '200-1500m', '8000', false, false, 'Trinket snakes can vibrate their tails to produce a rattling sound when threatened.'),
('indian-robin-snake', 'Indian Robin Snake', 'Calliophis maculiceps', 'A small, mildly venomous snake with distinctive dark markings. Found in forest undergrowth.', 'REPTILE', 'LEAST_CONCERN', 'RARE', 'Tropical and subtropical forests', '400-1800m', '2500', false, false, 'This species is one of the smallest elapid snakes in the world.'),
('keel-backed-racer', 'Keel-backed Racer', 'Platyceps kaulbacki', 'A fast-moving, non-venomous snake with keeled scales. Found in grasslands and scrub areas.', 'REPTILE', 'LEAST_CONCERN', 'COMMON', 'Grasslands, scrublands, and farmlands', '300-1500m', '4000', false, false, 'Racers can move at speeds exceeding 12 km/h over short distances.'),
('stripe-tailed-racer', 'Striped Pit Viper', 'Trimeresurus arcanus', 'A small, green pit viper with distinctive striping. Found in montane forests of eastern Nepal.', 'REPTILE', 'NEAR_THREATENED', 'RARE', 'Montane forests and bamboo thickets', '1000-2500m', '2000', false, false, 'This species was only described scientifically in 2002.'),
('yellow-spotted-pit-viper', 'Yellow-spotted Pit Viper', 'Trimeresurus flavomaculatus', 'A venomous pit viper with yellow spots on green background. Found in forests.', 'REPTILE', 'LEAST_CONCERN', 'COMMON', 'Tropical and subtropical forests', '500-2000m', '5000', false, false, 'Yellow-spotted pit vipers give birth to live young rather than laying eggs.'),
('red-lipped-pit-viper', 'Red-lipped Pit Viper', 'Trimeresurus erythrurus', 'A green pit viper with red lips and white lateral stripe. Found in eastern Nepal forests.', 'REPTILE', 'LEAST_CONCERN', 'COMMON', 'Dense forests and bamboo groves', '600-2200m', '3000', false, false, 'Males have a more vibrant red coloration on their lips than females.'),
('mountain-pit-viper', 'Mountain Pit Viper', 'Ovophis monticola', 'A venomous pit viper found at high elevations in the Himalayas. Brown with dark blotches.', 'REPTILE', 'LEAST_CONCERN', 'COMMON', 'Alpine meadows and rocky slopes', '2000-4000m', '2000', false, false, 'This species can survive temperatures below freezing by entering brumation.'),
('himalayan-pit-viper', 'Himalayan Pit Viper', 'Protobothrops himalayanus', 'A recently described venomous pit viper endemic to the Himalayas. Found at high elevations.', 'REPTILE', 'DATA_DEFICIENT', 'RARE', 'Alpine meadows and rocky terrain', '2500-4000m', '1000', false, false, 'This species was only discovered in 2014 and is known from just a few locations.'),
('common-house-gecko', 'Common House Gecko', 'Hemidactylus frenatus', 'A small, nocturnal gecko commonly found on walls of houses. Produces characteristic chirping sounds.', 'REPTILE', 'LEAST_CONCERN', 'COMMON', 'Urban areas, houses, and gardens', '0-2000m', '500000', false, false, 'Common house geckos can shed their tails when threatened, which continue to wriggle.'),
('brook-gecko', 'Brook''s House Gecko', 'Hemidactylus brookii', 'A large house gecko with distinctive tubercles on its back. Common in urban and rural areas.', 'REPTILE', 'LEAST_CONCERN', 'COMMON', 'Buildings, trees, and rock faces', '0-1500m', '100000', false, false, 'Brook geckos have adhesive pads that allow them to walk on vertical glass.'),
('garden-lizard-nepal', 'Garden Lizard', 'Calotes versicolor', 'A medium-sized lizard that can change color from brown to bright orange-red. Common in gardens.', 'REPTILE', 'LEAST_CONCERN', 'COMMON', 'Gardens, parks, and forest edges', '100-2000m', '200000', false, false, 'Garden lizards are also called ''bloodsuckers'' though they do not suck blood.'),
('skink-lizard', 'Six-striped Garden Skink', 'Eutropis carinata', 'A shiny, fast-moving skink with six distinct stripes. Found in gardens and forests.', 'REPTILE', 'LEAST_CONCERN', 'COMMON', 'Gardens, farmlands, and forests', '100-1500m', '80000', false, false, 'Skinks have reduced legs compared to other lizards, giving them a snake-like appearance.'),
('fan-throated-lizard', 'Fan-throated Lizard', 'Sitana ponticeriana', 'A small lizard with a distinctive colorful throat fan used in mating displays.', 'REPTILE', 'LEAST_CONCERN', 'COMMON', 'Dry grasslands, scrublands, and farmlands', '100-800m', '30000', false, false, 'Males display their colorful throat fans while doing push-ups to attract females.'),
('common-chameleon', 'Common Chameleon', 'Chamaeleo zeylanicus', 'One of the few chameleon species found in South Asia. Can change color for camouflage.', 'REPTILE', 'LEAST_CONCERN', 'COMMON', 'Forests, gardens, and scrublands', '200-1200m', '10000', false, false, 'Chameleons can move their eyes independently and have tongues twice their body length.'),
('clouded-monitor', 'Clouded Monitor Lizard', 'Varanus nebulosus', 'A large monitor lizard with clouded markings. Found in forests and riverine areas.', 'REPTILE', 'LEAST_CONCERN', 'COMMON', 'Tropical forests, riverbanks, and farmlands', '100-1500m', '5000', false, false, 'Clouded monitors can grow up to 1.5 meters and are excellent swimmers.'),
('indian-monitor', 'Indian Monitor Lizard', 'Varanus bengalensis', 'A large, powerful monitor lizard found across Nepal. Often seen basking in the sun.', 'REPTILE', 'LEAST_CONCERN', 'COMMON', 'Forests, farmlands, and urban areas', '100-1200m', '8000', false, false, 'Indian monitors can run at speeds up to 40 km/h in short bursts.'),
('angled-bent-toed-gecko', 'Angled Bent-toed Gecko', 'Cyrtodactylus albolatus', 'A small gecko with distinctive banding patterns and bent toes. Found in rocky areas.', 'REPTILE', 'LEAST_CONCERN', 'COMMON', 'Rocky outcrops, caves, and forest floors', '300-1500m', '5000', false, false, 'Bent-toed geckos lack the adhesive pads of house geckos and rely on claws.'),
('spotted-leopard-gecko', 'Spotted Leaf-toed Gecko', 'Hemidactylus triedrus', 'A medium-sized gecko with distinctive spots and leaf-like toe pads.', 'REPTILE', 'LEAST_CONCERN', 'COMMON', 'Rocky areas, caves, and old buildings', '200-1000m', '6000', false, false, 'This nocturnal species has excellent night vision and can see in near-total darkness.'),
('turkish-gecko', 'Mediterranean House Gecko', 'Hemidactylus turcicus', 'A small gecko with translucent skin that is expanding its range in South Asia.', 'REPTILE', 'LEAST_CONCERN', 'RARE', 'Urban areas and buildings', '100-500m', '2000', false, false, 'This species can produce sounds ranging from clicks to chirps.'),
('five-striped-palm-squirrel-lizard', 'Five-striped Calotes', 'Calotes calotes', 'A colorful lizard that turns bright red-orange during breeding season. Found in forests.', 'REPTILE', 'LEAST_CONCERN', 'COMMON', 'Forest edges, gardens, and farmlands', '200-1200m', '8000', false, false, 'Males become extremely territorial during breeding season and display bright colors.'),
('common-sun-skink', 'Many-lined Sun Skink', 'Eutropis multifasciata', 'A shiny, fast-moving skink with multiple light stripes. Common in tropical areas.', 'REPTILE', 'LEAST_CONCERN', 'COMMON', 'Gardens, farmlands, and forest edges', '100-1000m', '25000', false, false, 'Sun skinks bask in sunlight to regulate their body temperature.'),
('sivalensis-banded-lizard', 'Sivalik Fan-throated Lizard', 'Sitana sivalensis', 'A small lizard endemic to the Sivalik hills with a colorful throat fan.', 'REPTILE', 'VULNERABLE', 'RARE', 'Dry hills, scrublands, and grasslands', '300-800m', '3000', false, false, 'This species is found only in the Sivalik range of Nepal and India.'),
('spiny-tailed-lizard', 'Spiny-tailed Lizard', 'Uromastyx hardwickii', 'A large, herbivorous lizard with a spiny tail used for defense. Found in arid regions.', 'REPTILE', 'LEAST_CONCERN', 'RARE', 'Arid rocky areas and desert scrub', '300-800m', '2000', false, false, 'Spiny-tailed lizards are primarily herbivorous, unusual for large lizards.'),
('yellow-cricket-lizard', 'Yellow-bellied Garden Lizard', 'Calotes calotes calotes', 'A colorful garden lizard with a yellow belly. Common in farmlands and gardens.', 'REPTILE', 'LEAST_CONCERN', 'COMMON', 'Gardens, parks, and agricultural areas', '100-1500m', '40000', false, false, 'These lizards are beneficial to gardens as they eat large numbers of insects.'),
('blandford-lizard', 'Blandford''s Gecko', 'Hemidactylus brooki', 'A medium-sized gecko with distinctive banding. Found in the western Terai region.', 'REPTILE', 'LEAST_CONCERN', 'COMMON', 'Rocky areas and human settlements', '200-800m', '5000', false, false, 'This species is more active during twilight hours than full night.'),
('mountain-bent-toed-gecko', 'Mountain Bent-toed Gecko', 'Cyrtodactylus montanus', 'A small gecko adapted to montane environments. Found in rocky areas at moderate elevations.', 'REPTILE', 'NEAR_THREATENED', 'RARE', 'Montane forests and rocky slopes', '1000-2500m', '3000', false, false, 'Mountain bent-toed geckos are more cold-tolerant than lowland relatives.'),
('red-headed-racer', 'Red-headed Racer', 'Opheodrys major', 'A slender, bright green snake with a reddish head. Found in forests and gardens.', 'REPTILE', 'LEAST_CONCERN', 'COMMON', 'Forest edges, gardens, and farmlands', '300-1500m', '6000', false, false, 'Red-headed racers are excellent climbers and can leap between branches.'),
('himalayan-keelback', 'Himalayan Keelback', 'Helophis schokari', 'A small keelback adapted to high-altitude environments. Found near mountain streams.', 'REPTILE', 'LEAST_CONCERN', 'COMMON', 'Mountain streams and wet meadows', '2000-3500m', '4000', false, false, 'This species can survive near-freezing water temperatures.'),
('indian-flapshell', 'Indian Flapshell Turtle', 'Lissemys punctata', 'A freshwater turtle with distinctive flap-like plastron. Common in rivers and ponds.', 'REPTILE', 'LEAST_CONCERN', 'COMMON', 'Rivers, ponds, and marshes', '100-800m', '25000', false, false, 'Flapshell turtles can survive drought by burying themselves in mud.'),
('indian-black-turtle', 'Indian Black Turtle', 'Melanochelys trijuga', 'A medium-sized turtle with three distinct ridges on its shell. Found in wetlands.', 'REPTILE', 'LEAST_CONCERN', 'COMMON', 'Wetlands, ponds, and slow rivers', '100-1000m', '10000', false, false, 'Black turtles are more active during rainy season than dry season.'),
('indian-spot-turtle', 'Indian Spotted Turtle', 'Geoclemys hamiltonii', 'A small turtle with distinctive yellow spots on a dark shell. Endangered by pet trade.', 'REPTILE', 'ENDANGERED', 'RARE', 'Rivers, ponds, and wetlands', '100-600m', '5000', false, false, 'Hamilton''s turtles are heavily targeted by illegal pet traders.'),
('indian-star-tortoise', 'Indian Star Tortoise', 'Geochelone elegans', 'A beautiful tortoise with star-shaped patterns on its shell. Found in dry forests.', 'REPTILE', 'LEAST_CONCERN', 'COMMON', 'Dry deciduous forests and scrublands', '200-800m', '8000', false, false, 'Star tortoises can live for over 100 years in the wild.'),
('three-ridged-runner', 'Three-ridged Runner Turtle', 'Kachuga smithii', 'A medium-sized river turtle with three distinct ridges. Found in large rivers.', 'REPTILE', 'VULNERABLE', 'RARE', 'Large rivers and floodplains', '100-500m', '3000', false, false, 'Runner turtles are fast swimmers and can travel long distances in rivers.'),
('brown-roofed-turtle', 'Brown Roofed Turtle', 'Lissemys scutata', 'A freshwater turtle with a brown, domed shell. Found in rivers and lakes.', 'REPTILE', 'NEAR_THREATENED', 'RARE', 'Rivers, lakes, and marshes', '100-600m', '4000', false, false, 'Brown roofed turtles bask on logs and riverbanks during sunny mornings.'),
('rooftop-turtle', 'Rooftop Turtle', 'Pangshura tecta', 'A small turtle with a distinctive roof-like shell. Common in rivers and ponds.', 'REPTILE', 'LEAST_CONCERN', 'COMMON', 'Rivers, canals, and ponds', '100-800m', '15000', false, false, 'Rooftop turtles are popular in the pet trade due to their small size.'),
('brown-roofed-turtle-pangshura', 'Fasciated Roofed Turtle', 'Pangshura fasciata', 'A medium-sized turtle with banded shell patterns. Found in river systems.', 'REPTILE', 'LEAST_CONCERN', 'COMMON', 'Rivers and large streams', '100-600m', '7000', false, false, 'Fasciated turtles are more aquatic than other roofed turtle species.'),
('flapshell-turtle-pond', 'Flapshell Turtle', 'Hardella thurjii', 'A medium-sized turtle with a distinctive hinged plastron. Found in slow-moving waters.', 'REPTILE', 'VULNERABLE', 'RARE', 'Ponds, marshes, and slow rivers', '100-400m', '2000', false, false, 'This species is highly sensitive to water pollution.'),
('cantors-giant-softshell', 'Cantor''s Giant Softshell', 'Pelochelys cantorii', 'A massive softshell turtle that can grow up to 2 meters. One of the largest freshwater turtles.', 'REPTILE', 'VULNERABLE', 'RARE', 'Large rivers and estuaries', '0-200m', '1000', false, false, 'Cantor''s softshell turtles spend most of their time buried in sand underwater.'),
('indian-giant-softshell', 'Indian Giant Softshell', 'Chitra indica', 'A very large softshell turtle with a leathery shell. Found in major river systems.', 'REPTILE', 'VULNERABLE', 'RARE', 'Major rivers and floodplains', '100-400m', '2000', false, false, 'Giant softshells can weigh over 200 kg and are critically threatened.'),
('afghan-tortoise', 'Afghan Tortoise', 'Testudo horsfieldii', 'A small tortoise adapted to arid environments. Found in western Nepal.', 'REPTILE', 'VULNERABLE', 'RARE', 'Dry grasslands and rocky areas', '300-1000m', '3000', false, false, 'Afghan tortoises can enter estivation during extreme heat.'),
('four-clawed-gecko-turtle', 'Four-clawed Turtle', 'Mauremys reevesii', 'A medium-sized turtle with four-clawed feet. Found in ponds and slow rivers.', 'REPTILE', 'VULNERABLE', 'RARE', 'Ponds, lakes, and slow rivers', '100-500m', '2000', false, false, 'This species is one of the most common turtles in Asian cuisine.'),
('black-pond-turtle', 'Black Pond Turtle', 'Sacalia quadriocellata', 'A small turtle with distinctive eye-spots on its shell. Found in forest streams.', 'REPTILE', 'ENDANGERED', 'RARE', 'Forest streams and ponds', '200-800m', '1000', false, false, 'Black pond turtles are excellent climbers and can escape enclosures.'),
('european-pond-turtle', 'European Pond Turtle', 'Emys orbicularis', 'A medium-sized turtle with spotted shell. Found in Nepal''s western regions.', 'REPTILE', 'LEAST_CONCERN', 'RARE', 'Ponds, marshes, and slow streams', '200-600m', '1500', false, false, 'This species has the widest range of any turtle in the world.'),
('leaf-toed-gecko', 'Leaf-toed Gecko', 'Hemidactylus turcicus nepalicus', 'A subspecies of house gecko adapted to Nepal''s climate. Found in buildings and caves.', 'REPTILE', 'LEAST_CONCERN', 'COMMON', 'Buildings, caves, and rock faces', '100-1800m', '50000', false, false, 'Leaf-toed geckos have evolved specialized toe pads for climbing smooth surfaces.'),
('himalayan-gecko', 'Himalayan Gecko', 'Cyrtodactylus himalayanus', 'A small gecko adapted to high-altitude environments. Found in rocky areas.', 'REPTILE', 'NEAR_THREATENED', 'RARE', 'Alpine meadows and rocky slopes', '2000-4000m', '2000', false, false, 'This endemic species can survive temperatures well below freezing.'),
('medogensis-bent-toed-gecko', 'Medog Bent-toed Gecko', 'Cyrtodactylus medogensis', 'A recently discovered gecko species from eastern Nepal. Found in dense forests.', 'REPTILE', 'DATA_DEFICIENT', 'RARE', 'Tropical forests and caves', '500-1500m', '1000', false, false, 'This species was only discovered in 2018 and is known from very few specimens.'),
